import{_ as e,o as r,c as l,ag as i}from"./chunks/framework.BZohXCq9.js";const b=JSON.parse('{"title":"产品套件","description":"Bamdra OpenClaw 三个公开插件的整体介绍。","frontmatter":{"title":"产品套件","description":"Bamdra OpenClaw 三个公开插件的整体介绍。"},"headers":[],"relativePath":"zh/guide/products.md","filePath":"zh/guide/products.md","lastUpdated":null}'),o={name:"zh/guide/products.md"};function d(t,a,m,n,c,u){return r(),l("div",null,[...a[0]||(a[0]=[i('<h1 id="产品套件" tabindex="-1">产品套件 <a class="header-anchor" href="#产品套件" aria-label="Permalink to &quot;产品套件&quot;">​</a></h1><p>当前 Bamdra OpenClaw 套件以 3 个公开插件形式发布，而且这 3 个插件都可以独立运行。</p><h2 id="bamdra-openclaw-memory" tabindex="-1">bamdra-openclaw-memory <a class="header-anchor" href="#bamdra-openclaw-memory" aria-label="Permalink to &quot;bamdra-openclaw-memory&quot;">​</a></h2><p>面向 OpenClaw 的 continuity-first 主记忆运行时。</p><ul><li>话题连续性</li><li>稳定事实存储</li><li>紧凑上下文装配</li><li>自动补齐宿主配置、本地 memory 目录和 bundled 身份依赖</li></ul><p>进一步阅读：</p><ul><li><a href="/zh/guide/openclaw-topic-memory">bamdra-openclaw-memory</a></li></ul><h2 id="bamdra-user-bind" tabindex="-1">bamdra-user-bind <a class="header-anchor" href="#bamdra-user-bind" aria-label="Permalink to &quot;bamdra-user-bind&quot;">​</a></h2><p>身份绑定与画像插件。</p><ul><li>把各类 channel 暴露出的 sender ID 解析成稳定用户边界</li><li>在本地存储用户画像与映射关系</li><li>支持飞书身份解析工作流</li><li>也可以独立给别的运行时提供用户身份归一化能力</li></ul><p>进一步阅读：</p><ul><li><a href="/zh/guide/user-bind">bamdra-user-bind</a></li></ul><h2 id="bamdra-memory-vector" tabindex="-1">bamdra-memory-vector <a class="header-anchor" href="#bamdra-memory-vector" aria-label="Permalink to &quot;bamdra-memory-vector&quot;">​</a></h2><p>语义召回增强插件。</p><ul><li>保持 Markdown 可读记忆</li><li>增加轻量本地语义检索</li><li>可以配合 <code>bamdra-openclaw-memory</code> 使用，也可以单独作为检索工具运行</li></ul><p>进一步阅读：</p><ul><li><a href="/zh/guide/memory-vector">bamdra-memory-vector</a></li></ul><h2 id="它们之间的关系" tabindex="-1">它们之间的关系 <a class="header-anchor" href="#它们之间的关系" aria-label="Permalink to &quot;它们之间的关系&quot;">​</a></h2><ul><li><code>bamdra-openclaw-memory</code> 可以单独运行</li><li>通过 npm 安装 <code>bamdra-openclaw-memory</code> 时，如果本地缺少 <code>bamdra-user-bind</code>，主插件会自动把这个依赖补齐到 OpenClaw 扩展目录</li><li><code>bamdra-memory-vector</code> 保持可选增强，不会被强行塞进主插件里</li></ul><h2 id="github" tabindex="-1">GitHub <a class="header-anchor" href="#github" aria-label="Permalink to &quot;GitHub&quot;">​</a></h2><p>全部仓库入口：</p><ul><li><a href="https://github.com/bamdra" target="_blank" rel="noreferrer">github.com/bamdra</a></li></ul>',22)])])}const h=e(o,[["render",d]]);export{b as __pageData,h as default};
